ENTRY.C_INTEREST_RATE1:
var ccy1 = DV.getFieldValue("CR_CCY");
var ccy2 = DV.getFieldValue('SETT_CCY');
var baseCCY = DV.SYS_LCY;
var rate = '123456789';
var cnty = DV.getCountryCode();
DV.writeLog("Dr - ccy1 " + ccy1 + " ccy2 " + ccy2);
if (ccy1.equals(baseCCY) || ccy2.equals(baseCCY) ){
  DV.appendField(rate);
}else{
  sql = "C_FROM_CCY = '"+ ccy1 +"' AND C_TO_CCY='"+baseCCY+"' and C_BK_GROUP_ID='STBANK' and C_CNTY_CODE='"+cnty+"' and C_DESC_ID='Booking Rate' "; 	
  DV.SYS_getTableData('F_VALUE','EXIMSYS.STD_EXCHAN_RATE',sql);		
}

ENTRY.C_GL:
var cash=DV.getCurrentDoData('MUL_CASH_IND');
if (cash ==  'Yes'){
  var country = DV.getCountryCode();
  var currency=DV.getCurrentDoData('SETT_CCY');
  var sql = "item_c='006' and cnty_code='" + country + "' and item_name='" + currency + "'" ;
  DV.SYS_getTableData('FIELD_1_X','eximtrx.data_master',sql);
} else {
  var acc;
  acc = DV.getCurrentDoData('CPYT_DR_AC');
  DV.appendField(acc);
}

ENTRY.C_INTEREST_RATE1:
var ccy1 = DV.getCurrentDoData('SETT_CCY');
var ccy2 = DV.getCurrentDoData('PAY_CCY');
var baseCCY = DV.SYS_LCY;
var rate = '123456789';
var cnty = DV.getCountryCode();
if (ccy1.equals(baseCCY) || ccy2.equals(baseCCY) ){
  DV.appendField(rate);
}else{
	sql = "C_FROM_CCY = '"+ ccy1 +"' AND C_TO_CCY='"+baseCCY+"' and C_BK_GROUP_ID='STBANK' and C_CNTY_CODE='"+cnty+"' and C_DESC_ID='Booking Rate' "; 
  DV.SYS_getTableData('F_VALUE','EXIMSYS.STD_EXCHAN_RATE',sql);	
}

ENTRY.C_REF_NUMBER:
var type;
  var cash=DV.getCurrentDoData('MUL_CASH_IND');
  if (cash.equals('No')){
    type =DV.getCurrentDoData('CPYT_DR_AC_TYPE');
  }else{
    type ='BANK';
  }
  DV.appendField(type);

ENTRY.C_VCH_SPECIAL1:
